import{_ as e,o as t,c as n,ag as s}from"./chunks/framework.DEqXEGcv.js";const u=JSON.parse('{"title":"什么是 RDE","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/guide/what-is-rde.md","filePath":"zh/docs/guide/what-is-rde.md"}'),r={name:"zh/docs/guide/what-is-rde.md"};function i(l,a,o,d,h,p){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="什么是-rde" tabindex="-1">什么是 RDE <a class="header-anchor" href="#什么是-rde" aria-label="Permalink to &quot;什么是 RDE&quot;">​</a></h1><p><strong>RDE</strong>（Ruizi Desktop Environment，瑞子云桌面）是一个开源的 Web 桌面环境，将 Linux 服务器变成功能丰富的云桌面。通过浏览器即可获得类 Windows 的操作体验，涵盖文件管理、Docker 应用、系统监控等功能。</p><h2 id="为什么选择-rde" tabindex="-1">为什么选择 RDE？ <a class="header-anchor" href="#为什么选择-rde" aria-label="Permalink to &quot;为什么选择 RDE？&quot;">​</a></h2><ul><li><strong>无需安装桌面环境</strong>：不占用服务器资源安装 GNOME/KDE，通过 Web 即可操作</li><li><strong>随时随地访问</strong>：浏览器打开即用，支持手机、平板、电脑</li><li><strong>功能丰富</strong>：文件管理、Docker 应用商店、音视频播放、下载管理等一应俱全</li><li><strong>开源免费</strong>：核心功能全部开源，GPL-3.0 协议</li></ul><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><h3 id="🖥️-web-桌面体验" tabindex="-1">🖥️ Web 桌面体验 <a class="header-anchor" href="#🖥️-web-桌面体验" aria-label="Permalink to &quot;🖥️ Web 桌面体验&quot;">​</a></h3><p>类 Windows 的窗口管理器，支持拖拽、缩放、最大化、最小化，任务栏、右键菜单，在浏览器中获得桌面级操作体验。支持 iframe/组件/弹窗三种窗口类型。</p><h3 id="📁-文件管理" tabindex="-1">📁 文件管理 <a class="header-anchor" href="#📁-文件管理" aria-label="Permalink to &quot;📁 文件管理&quot;">​</a></h3><p>功能完整的文件管理器，支持上传、下载、预览、分享。大文件使用 TUS 协议断点续传，支持 10GB+ 文件上传。</p><h3 id="🐳-docker-应用商店" tabindex="-1">🐳 Docker 应用商店 <a class="header-anchor" href="#🐳-docker-应用商店" aria-label="Permalink to &quot;🐳 Docker 应用商店&quot;">​</a></h3><p>可视化管理 Docker 容器和镜像，一键部署常用应用，无需记忆复杂的命令行参数。</p><h3 id="💻-web-终端" tabindex="-1">💻 Web 终端 <a class="header-anchor" href="#💻-web-终端" aria-label="Permalink to &quot;💻 Web 终端&quot;">​</a></h3><p>基于 xterm.js + WebSocket + PTY 的 Web 终端，浏览器内即可使用完整的 Linux Shell，支持多会话管理、主题切换。</p><h3 id="📦-更多内置应用" tabindex="-1">📦 更多内置应用 <a class="header-anchor" href="#📦-更多内置应用" aria-label="Permalink to &quot;📦 更多内置应用&quot;">​</a></h3><ul><li><strong>下载管理</strong>：基于 Aria2，支持 HTTP/BT/磁力链接</li><li><strong>音乐播放器</strong>：歌词显示、音频可视化、多种播放模式</li><li><strong>视频播放器</strong>：多格式播放，ffmpeg 实时 HLS 转码</li><li><strong>相册</strong>：照片元数据提取，缩略图生成，类群晖体验</li><li><strong>复古游戏</strong>：WebAssembly 模拟器，NES/SNES/GBA/PS1 等经典平台</li><li><strong>Flatpak 应用</strong>：在浏览器中运行 Linux GUI 应用</li></ul><h3 id="🔌-插件系统" tabindex="-1">🔌 插件系统 <a class="header-anchor" href="#🔌-插件系统" aria-label="Permalink to &quot;🔌 插件系统&quot;">​</a></h3><p>通过 Unix Socket HTTP 通信的插件机制，支持热插拔加载，轻松扩展更多功能。</p><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>技术</th></tr></thead><tbody><tr><td>后端</td><td>Go、Gin、GORM、SQLite</td></tr><tr><td>前端</td><td>Svelte 5、SvelteKit、Tailwind CSS v4、Vite</td></tr><tr><td>容器</td><td>Docker API</td></tr><tr><td>下载</td><td>Aria2 RPC</td></tr><tr><td>插件</td><td>Unix Socket HTTP 通信</td></tr></tbody></table><h2 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器 → RDE 服务端 (Go + SQLite)</span></span>
<span class="line"><span>          ├── 桌面环境 (SvelteKit)</span></span>
<span class="line"><span>          │   ├── 窗口管理器</span></span>
<span class="line"><span>          │   ├── 任务栏</span></span>
<span class="line"><span>          │   └── 应用 UI</span></span>
<span class="line"><span>          ├── 功能模块</span></span>
<span class="line"><span>          │   ├── 文件管理</span></span>
<span class="line"><span>          │   ├── Docker 管理</span></span>
<span class="line"><span>          │   ├── 终端服务</span></span>
<span class="line"><span>          │   ├── 下载管理</span></span>
<span class="line"><span>          │   └── 备份还原</span></span>
<span class="line"><span>          └── 插件系统</span></span></code></pre></div><h2 id="增值服务" tabindex="-1">增值服务 <a class="header-anchor" href="#增值服务" aria-label="Permalink to &quot;增值服务&quot;">​</a></h2><p>RDE 的所有开源功能永久免费。同时提供可选的付费增值服务：</p><ul><li><strong>Docker 镜像加速</strong>：内置 Registry 反向代理，国内拉取镜像不再超时</li><li><strong>云备份</strong>：系统配置和用户数据自动备份到云端</li><li><strong>AI 助手</strong>：DeepSeek 驱动的智能对话</li><li><strong>安卓模拟器</strong>：在云桌面中运行安卓应用</li><li><strong>虚拟机</strong>：QEMU/KVM 虚拟机管理</li></ul><p>详见 <a href="/shop.html">会员方案</a>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/zh/docs/guide/getting-started.html">快速开始</a> — 5 分钟安装上手</li><li><a href="/zh/docs/guide/installation.html">安装部署</a> — 详细部署指南</li></ul>`,27)])])}const b=e(r,[["render",i]]);export{u as __pageData,b as default};
